var state = {
  activeCategory: 'All Courses',
  coursesData: COURSES.slice(),
  revealObserver: null
};


/* ----------------------------------------------------------------
   6. RENDER — CATEGORIES
   ---------------------------------------------------------------- */
function renderCategories() {
  var row = document.getElementById('categoriesRow');
  if (!row) return;
  row.innerHTML = '';

  CATEGORIES.forEach(function (cat) {
    var btn = document.createElement('button');
    btn.className = 'cat-tab' + (cat === state.activeCategory ? ' active' : '');
    btn.textContent = cat;
    btn.setAttribute('role', 'tab');
    btn.setAttribute('aria-selected', cat === state.activeCategory ? 'true' : 'false');
    btn.onclick = function () {
      state.activeCategory = cat;
      renderCategories();
      renderCourses();
    };
    row.appendChild(btn);
  });
}


/* ----------------------------------------------------------------
   7. RENDER — COURSES
   ---------------------------------------------------------------- */
function renderCourses() {
  var grid  = document.getElementById('coursesGrid');
  var count = document.getElementById('coursesCount');
  if (!grid) return;
  grid.innerHTML = '';

  var filtered = state.activeCategory === 'All Courses'
    ? state.coursesData
    : state.coursesData.filter(function (c) { return c.category === state.activeCategory; });

  if (count) {
    var n = filtered.length;
    count.innerHTML = 'Showing <strong>' + n + '</strong> course' + (n !== 1 ? 's' : '');
  }

  if (filtered.length === 0) {
    grid.innerHTML = '<p style="color:var(--gray-400);font-size:0.9rem;grid-column:1/-1;padding:40px 0;">No courses found in this category.</p>';
    return;
  }

  filtered.forEach(function (course, i) {
    var card = document.createElement('article');
    card.className = 'course-card reveal reveal-d' + ((i % 4) + 1);
    card.setAttribute('role', 'listitem');
    card.setAttribute('aria-label', course.title);

    var tagHtml = course.tag
      ? '<div class="card-thumb-tag ' + course.tagCls + '" aria-label="' + course.tag + '">' + course.tag + '</div>'
      : '';

    var starsHtml = '★★★★★';

    card.innerHTML = [
      '<div class="card-thumb" style="background:' + course.bg + '">',
        '<img src="' + course.image + '" alt="" loading="lazy">',
        tagHtml,
      '</div>',
      '<div class="card-body">',
        '<div class="card-category">' + course.category + '</div>',
        '<h3 class="card-title">' + course.title + '</h3>',
        '<p class="card-desc">' + course.desc + '</p>',
        '<div class="card-meta">',
          '<div class="card-meta-item">',
            '<svg viewBox="0 0 24 24" aria-hidden="true"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg>',
            escapeHtml(course.duration),
          '</div>',
          '<div class="card-meta-item">',
            '<svg viewBox="0 0 24 24" aria-hidden="true"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18"/></svg>',
            escapeHtml(course.sessions),
          '</div>',
          '<div class="card-rating" aria-label="Rating ' + course.rating + ' out of 5, ' + course.reviews.toLocaleString('en-IN') + ' reviews">',
            '<span class="stars" aria-hidden="true">' + starsHtml + '</span>',
            course.rating + ' (' + course.reviews.toLocaleString('en-IN') + ')',
          '</div>',
        '</div>',
        '<div class="card-footer">',
          '<div class="card-level">',
            '<span class="level-dot ' + course.levelCls + '" aria-hidden="true"></span>',
            escapeHtml(course.levelLabel),
          '</div>',
          '<button class="card-enroll ' + course.enrolCls + '" onclick="window.location.href=\'course.html?course=' + course.id + '\'">',
  escapeHtml(course.enrolLabel),
'</button>',
        '</div>',
      '</div>'
    ].join('');

    grid.appendChild(card);
  });

  triggerReveal();
}


/* ----------------------------------------------------------------
   8. SORT HANDLER
   ---------------------------------------------------------------- */
function handleSort() {
  var sel = document.getElementById('sortSelect');
  if (!sel) return;
  var val = sel.value;

  if (val === 'rating') {
    state.coursesData.sort(function (a, b) { return b.rating - a.rating; });
  } else if (val === 'newest') {
    state.coursesData.sort(function (a, b) { return b.order - a.order; });
  } else if (val === 'popular') {
    state.coursesData.sort(function (a, b) { return b.reviews - a.reviews; });
  }

  renderCourses();
}


