/* ----------------------------------------------------------------
   11. FAQ TOGGLE
   ---------------------------------------------------------------- */
function toggleFaq(btn) {
  var item   = btn.closest('.faq-item');
  var isOpen = item.classList.contains('open');

  /* Close all */
  document.querySelectorAll('.faq-item.open').forEach(function (el) {
    el.classList.remove('open');
    var q = el.querySelector('.faq-q');
    if (q) {
      q.classList.remove('open');
      q.setAttribute('aria-expanded', 'false');
    }
  });

  /* Open clicked (if it was closed) */
  if (!isOpen) {
    item.classList.add('open');
    btn.classList.add('open');
    btn.setAttribute('aria-expanded', 'true');
  }
}


/* ----------------------------------------------------------------
   12. PAGE NAVIGATION
   ---------------------------------------------------------------- */
function showPage(name) {
  /* Hide all pages */
  document.querySelectorAll('.page').forEach(function (p) {
    p.classList.remove('active');
  });

  /* Deactivate all nav links */
  document.querySelectorAll('.nav-menu a[id]').forEach(function (a) {
    a.classList.remove('active');
  });

  /* Show target page */
  var page = document.getElementById('page-' + name);
  if (page) { page.classList.add('active'); }

  /* Activate nav link */
  var navEl = document.getElementById('nav-' + name);
  if (navEl) { navEl.classList.add('active'); }

  /* Scroll & close menu */
  window.scrollTo({ top: 0, behavior: 'smooth' });
  closeMenu();

  /* Trigger reveal for new page content */
  setTimeout(triggerReveal, 120);
}


/* ----------------------------------------------------------------
   13. MOBILE MENU
   ---------------------------------------------------------------- */
function toggleMenu() {
  var menu = document.getElementById('navMenu');
  var btn  = document.getElementById('hamburgerBtn');
  if (!menu || !btn) return;

  var isOpen = menu.classList.toggle('open');
  btn.classList.toggle('open', isOpen);
  btn.setAttribute('aria-expanded', isOpen ? 'true' : 'false');
}

function closeMenu() {
  var menu = document.getElementById('navMenu');
  var btn  = document.getElementById('hamburgerBtn');
  if (!menu || !btn) return;
  menu.classList.remove('open');
  btn.classList.remove('open');
  btn.setAttribute('aria-expanded', 'false');
}


/* ----------------------------------------------------------------
   14. CONTACT FORM
   ---------------------------------------------------------------- */
function submitContact(e) {
  e.preventDefault();
  var form    = document.getElementById('contactForm');
  var success = document.getElementById('formSuccess');
  if (!form || !success) return;

  /* Basic validation */
  var requiredFields = form.querySelectorAll('[required]');
  var valid = true;

  requiredFields.forEach(function (field) {
    field.style.borderColor = '';
    if (!field.value.trim()) {
      field.style.borderColor = '#e05252';
      valid = false;
    }
  });

  if (!valid) return;

  /* Simulate submission */
  form.style.display = 'none';
  success.style.display = 'block';
}


/* ----------------------------------------------------------------
   15. SCROLL REVEAL
   ---------------------------------------------------------------- */
function triggerReveal() {
  var targets = document.querySelectorAll('.reveal:not(.in)');
  if (targets.length === 0) return;

  if (!state.revealObserver) {
    state.revealObserver = new IntersectionObserver(function (entries) {
      entries.forEach(function (entry) {
        if (entry.isIntersecting) {
          entry.target.classList.add('in');
          state.revealObserver.unobserve(entry.target);
        }
      });
    }, { threshold: 0.06, rootMargin: '0px 0px -32px 0px' });
  }

  targets.forEach(function (el) {
    state.revealObserver.observe(el);
  });
}


/* ----------------------------------------------------------------
   16. NAVBAR SCROLL EFFECT
   ---------------------------------------------------------------- */
function initNavbarScroll() {
  var navbar = document.getElementById('navbar');
  if (!navbar) return;

  window.addEventListener('scroll', function () {
    if (window.scrollY > 10) {
      navbar.classList.add('scrolled');
    } else {
      navbar.classList.remove('scrolled');
    }
  }, { passive: true });
}


/* ----------------------------------------------------------------
   17. KEYBOARD NAVIGATION
   ---------------------------------------------------------------- */
function initKeyboardNav() {
  /* Close mobile menu on Escape */
  document.addEventListener('keydown', function (e) {
    if (e.key === 'Escape') { closeMenu(); }
  });

  /* Allow logo / buttons to be triggered with Enter/Space */
  document.addEventListener('keydown', function (e) {
    if (e.key === 'Enter' || e.key === ' ') {
      var el = document.activeElement;
      if (el && el.getAttribute('role') === 'button' && el.tagName !== 'BUTTON') {
        e.preventDefault();
        el.click();
      }
    }
  });
}


/* ----------------------------------------------------------------
   18. UTILITY — HTML ESCAPE
   ---------------------------------------------------------------- */
function escapeHtml(str) {
  if (str == null) return '';
  return String(str)
    .replace(/&/g,  '&amp;')
    .replace(/</g,  '&lt;')
    .replace(/>/g,  '&gt;')
    .replace(/"/g,  '&quot;')
    .replace(/'/g,  '&#039;');
}


/* ----------------------------------------------------------------
   19. INIT
   ---------------------------------------------------------------- */
(function init() {
  renderCategories();
  renderCourses();
  renderTestimonials();
  renderFAQ();
  initNavbarScroll();
  initKeyboardNav();

  /* Initial reveal pass */
  window.addEventListener('scroll', triggerReveal, { passive: true });
  setTimeout(triggerReveal, 200);
})();